ETF_CODES = set(ETF_CONSTITUENTS.keys())

UNRESOLVED_ETF_CONSTITUENTS = {
    '513520.SH': 'No donor-backed constituent basket found in legacy service scripts; breadth remains 0/0 until a verified Nikkei basket is supplied.',
}

BREADTH_ELIGIBLE_ETF_CODES = ETF_CODES - set(UNRESOLVED_ETF_CONSTITUENTS.keys())


def _get_timeframe_config():
    return TIMEFRAME_CONFIGS.get(TIMEFRAME_MODE, TIMEFRAME_CONFIGS["daily"])

def _ensure_db(db_path):
    os.makedirs(os.path.dirname(db_path), exist_ok=True)
    conn = sqlite3.connect(db_path)
    c = conn.cursor()

    # Latest snapshot: one row per ETF, replaced on every bar
    c.execute("""
        CREATE TABLE IF NOT EXISTS latest_snapshot (
            etf_code         TEXT PRIMARY KEY,
            etf_name         TEXT,
            industry         TEXT,
            close            REAL,
            m5               REAL,
            m10              REAL,
            m20              REAL,
            m0               REAL,
            greater_m5       INTEGER,
            greater_m10      INTEGER,
            greater_m20      INTEGER,
            greater_m0       INTEGER,
            hold_status      INTEGER,
            buy_sell_signal  TEXT,
            m0_percent       REAL,
            m5_percent       REAL,
            m10_percent      REAL,
            m20_percent      REAL,
            ma_mean_ratio    REAL,
            growth_stock_count  INTEGER,
            total_stock_count   INTEGER,
            total_score      INTEGER,
            create_time      TEXT
        )
    """)

    # Timeseries: full history, used by stockTimeseries page
    c.execute("""
        CREATE TABLE IF NOT EXISTS timeseries (
            id               INTEGER PRIMARY KEY AUTOINCREMENT,
            etf_code         TEXT,
            etf_name         TEXT,
            industry         TEXT,
            close            REAL,
            m5               REAL,
            m10              REAL,
            m20              REAL,
            m0               REAL,
            greater_m5       INTEGER,
            greater_m10      INTEGER,
            greater_m20      INTEGER,
            greater_m0       INTEGER,
            hold_status      INTEGER,
            buy_sell_signal  TEXT,
            m0_percent       REAL,
            m5_percent       REAL,
            m10_percent      REAL,
            m20_percent      REAL,
            ma_mean_ratio    REAL,
            growth_stock_count  INTEGER,
            total_stock_count   INTEGER,
            total_score      INTEGER,
            create_time      TEXT
        )
    """)
    c.execute("CREATE INDEX IF NOT EXISTS idx_ts_code_time ON timeseries(etf_code, create_time)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_ts_time ON timeseries(create_time)")

    existing_snapshot_columns = set(
        row[1] for row in c.execute("PRAGMA table_info(latest_snapshot)").fetchall()
    )
    if "buy_sell_signal" not in existing_snapshot_columns:
        c.execute("ALTER TABLE latest_snapshot ADD COLUMN buy_sell_signal TEXT")

    existing_timeseries_columns = set(
        row[1] for row in c.execute("PRAGMA table_info(timeseries)").fetchall()
    )
    if "buy_sell_signal" not in existing_timeseries_columns:
        c.execute("ALTER TABLE timeseries ADD COLUMN buy_sell_signal TEXT")

    conn.commit()
    conn.close()


def _safe_float(val, default=0.0):
    try:
        return float(val)
    except Exception:
        return default


def _calc_ma(prices, period):
    if len(prices) < period:
        return None
    return sum(prices[-period:]) / period


def _get_history_closes(ContextInfo, stock_code, period, count):
    try:
        history = ContextInfo.get_market_data(
            fields=["close"],
            stock_code=[stock_code],
            period=period,
            count=count,
            dividend_type="none",
        )
    except Exception:
        return []

    if history is None or history.empty:
        return []

    return [_safe_float(v) for v in history["close"].tolist()]


def _get_lookback_price(ContextInfo, stock_code, tick, lookback_minutes):
    if lookback_minutes <= 0:
        return _safe_float(tick.get("lastClose"))

    closes = _get_history_closes(ContextInfo, stock_code, "1m", lookback_minutes)
    if len(closes) >= lookback_minutes:
        return closes[0]

    return _safe_float(tick.get("lastClose"))


def _get_etf_line_values(ContextInfo, full_code, current_price, tf_config):
    ma_windows = tf_config["ma_windows"]
    label_windows = tf_config["label_windows"]
    period = tf_config["period"]
    history_count = max(ma_windows) - 1
    closes = _get_history_closes(ContextInfo, full_code, period, history_count)

    ma_values = {}
    for label_window, actual_window in zip(label_windows, ma_windows):
        req = actual_window - 1
        if len(closes) < req:
            ma_values[label_window] = 0.0
            continue

        prices_for_ma = closes[-req:] + [current_price]
        if len(prices_for_ma) != actual_window:
            ma_values[label_window] = 0.0
            continue

        ma_values[label_window] = round(sum(prices_for_ma) / actual_window, 4)

    return ma_values


def _total_score(row):
    score = 0
    threshold = 0.5

    if row.get("m5_percent", 0.0) >= threshold:
        score += 1
    if row.get("m10_percent", 0.0) >= threshold:
        score += 1
    if row.get("m20_percent", 0.0) >= threshold:
        score += 1
    if row.get("ma_mean_ratio", 0.0) >= threshold:
        score += 1

    if row["greater_m5"]:
        score += 1
    if row["greater_m10"]:
        score += 1
    if row["greater_m20"]:
        score += 1

    return score


def _buy_sell_signal(total_score):
    if total_score is None:
        return None
    return "BUY" if total_score >= 4 else "SELL"


def _purge_old_records(conn, days):
    cutoff = time.strftime(
        "%Y-%m-%d %H:%M:%S",
        time.localtime(time.time() - days * 86400)
    )
    conn.execute("DELETE FROM timeseries WHERE create_time < ?", (cutoff,))


def _get_constituent_codes(code, mkt):
    full_code = "{0}.{1}".format(code, mkt)
    constituents = ETF_CONSTITUENTS.get(full_code)
    if not constituents:
        return []
    return [c for c in constituents if c != full_code]


def _get_constituent_statistics(ContextInfo, code, mkt, tf_config):
    full_code = "{0}.{1}".format(code, mkt)
    constituent_codes = _get_constituent_codes(code, mkt)
    if not constituent_codes:
        return (None, None) if full_code not in BREADTH_ELIGIBLE_ETF_CODES else (0, 0)

    try:
        full_tick = ContextInfo.get_full_tick(constituent_codes)
    except Exception:
        full_tick = {}

    total_count = 0
    rise_count = 0
    lookback_minutes = tf_config.get("m0_lookback_minutes", 0)
    for stock_code in constituent_codes:
        tick = full_tick.get(stock_code)
        if not tick:
            continue
        try:
            last_price = float(tick["lastPrice"])
        except Exception:
            continue

        compare_price = _get_lookback_price(ContextInfo, stock_code, tick, lookback_minutes)
        total_count += 1
        if last_price > compare_price:
            rise_count += 1

    return rise_count, total_count


def _get_constituent_ma_statistics(ContextInfo, code, mkt, tf_config):
    full_code = "{0}.{1}".format(code, mkt)
    constituent_codes = _get_constituent_codes(code, mkt)
    windows = tf_config["ma_windows"]
    label_windows = tf_config["label_windows"]
    period = tf_config["period"]
    history_count = max(windows) - 1
    if not constituent_codes:
        if full_code not in BREADTH_ELIGIBLE_ETF_CODES:
            return dict((window, None) for window in label_windows), None
        return dict((window, 0.0) for window in label_windows), 0

    try:
        full_tick = ContextInfo.get_full_tick(constituent_codes)
    except Exception:
        full_tick = {}

    total_count = 0
    rise_counts = dict((window, 0) for window in label_windows)

    for stock_code in constituent_codes:
        tick = full_tick.get(stock_code)
        if not tick:
            continue

        try:
            last_price = float(tick["lastPrice"])
        except Exception:
            continue

        total_count += 1
        closes = _get_history_closes(ContextInfo, stock_code, period, history_count)

        for label_window, actual_window in zip(label_windows, windows):
            req = actual_window - 1
            if len(closes) < req:
                continue

            prices_for_ma = closes[-req:] + [last_price]
            if len(prices_for_ma) != actual_window:
                continue

            ma_value = sum(prices_for_ma) / actual_window
            if last_price > ma_value:
                rise_counts[label_window] += 1

    percents = {}
    for window in label_windows:
        percents[window] = round(rise_counts[window] / total_count, 4) if total_count else 0.0

    return percents, total_count


def init(ContextInfo):
    codes = ["{0}.{1}".format(code, mkt) for code, mkt, _, _ in UNIVERSE]
    ContextInfo.set_universe(codes)
    _ensure_db(DB_PATH)
    print("[DataExport] init OK, DB=" + DB_PATH)
    if getattr(ContextInfo, "do_back_test", False):
        print("[DataExport] WARNING: BACKTEST mode - switch to LIVE (run) mode to export real data.")


def handlebar(ContextInfo):
    # do_back_test is True in backtest mode - no live quotes available, skip
    if getattr(ContextInfo, "do_back_test", False):
        return

    now_str = time.strftime("%Y-%m-%d %H:%M:%S", time.localtime())
    tf_config = _get_timeframe_config()

    rows = []

    for code, mkt, name, industry in UNIVERSE:
        full_code = "{0}.{1}".format(code, mkt)

        try:
            try:
                full_tick = ContextInfo.get_full_tick([full_code])
            except Exception:
                full_tick = {}

            etf_tick = full_tick.get(full_code)
            if etf_tick and etf_tick.get("lastPrice") is not None:
                current_close = _safe_float(etf_tick.get("lastPrice"))
                last_close = _safe_float(etf_tick.get("lastClose"))
            else:
                closes = _get_history_closes(ContextInfo, full_code, tf_config["period"], max(tf_config["ma_windows"]))
                if not closes:
                    continue
                current_close = closes[-1]
                last_close = closes[-2] if len(closes) > 1 else current_close
                etf_tick = {"lastPrice": current_close, "lastClose": last_close}

            ma_values = _get_etf_line_values(ContextInfo, full_code, current_close, tf_config)
            m5 = ma_values.get(5, 0.0)
            m10 = ma_values.get(10, 0.0)
            m20 = ma_values.get(20, 0.0)
            compare_price = _get_lookback_price(ContextInfo, full_code, etf_tick, tf_config.get("m0_lookback_minutes", 0))

            greater_m5 = current_close > m5 if m5 else False
            greater_m10 = current_close > m10 if m10 else False
            greater_m20 = current_close > m20 if m20 else False
            greater_m0 = current_close > compare_price if compare_price else False

            if full_code in ETF_CODES:
                rise_count, total_count = _get_constituent_statistics(ContextInfo, code, mkt, tf_config)
                ma_percents, ma_total_count = _get_constituent_ma_statistics(ContextInfo, code, mkt, tf_config)
                if ma_total_count is not None:
                    total_count = ma_total_count

                m5_pct = ma_percents.get(5)
                m10_pct = ma_percents.get(10)
                m20_pct = ma_percents.get(20)
                m0_pct = round(rise_count / total_count, 4) if total_count else (0.0 if total_count == 0 else None)
                ma_mean_ratio = (
                    round((m5_pct + m10_pct + m20_pct) / 3, 4)
                    if total_count and None not in (m5_pct, m10_pct, m20_pct)
                    else (0.0 if total_count == 0 else None)
                )
            else:
                rise_count = None
                total_count = None
                m0_pct = 1.0 if greater_m0 else 0.0
                m5_pct = 1.0 if greater_m5 else 0.0
                m10_pct = 1.0 if greater_m10 else 0.0
                m20_pct = 1.0 if greater_m20 else 0.0
                ma_mean_ratio = round((m5_pct + m10_pct + m20_pct) / 3.0, 4)

            row = {
                "etf_code":    code,
                "etf_name":    name,
                "industry":    industry,
                "close":       current_close,
                "m5":          m5,
                "m10":         m10,
                "m20":         m20,
                "m0":          compare_price,
                "greater_m5":  int(greater_m5),
                "greater_m10": int(greater_m10),
                "greater_m20": int(greater_m20),
                "greater_m0":  int(greater_m0),
                "hold_status": int(greater_m5 and greater_m10),
                "m0_percent":  m0_pct,
                "m5_percent":  m5_pct,
                "m10_percent": m10_pct,
                "m20_percent": m20_pct,
                "ma_mean_ratio": ma_mean_ratio,
                "growth_stock_count": rise_count,
                "total_stock_count":  total_count,
                "create_time": now_str,
            }
            row["total_score"] = _total_score(row)
            row["buy_sell_signal"] = _buy_sell_signal(row["total_score"])
            rows.append(row)

        except Exception as e:
            print("[DataExport] error {0}: {1}".format(full_code, e))

    if not rows:
        print("[DataExport] no data collected, skipping DB write")
        return

    try:
        conn = sqlite3.connect(DB_PATH, timeout=5)

        cols = [
            "etf_code", "etf_name", "industry", "close",
            "m5", "m10", "m20", "m0",
            "greater_m5", "greater_m10", "greater_m20", "greater_m0",
            "hold_status", "buy_sell_signal", "m0_percent", "m5_percent", "m10_percent",
            "m20_percent", "ma_mean_ratio", "growth_stock_count",
            "total_stock_count", "total_score", "create_time",
        ]
        placeholders = ", ".join(["?"] * len(cols))
        col_names    = ", ".join(cols)

        upsert_sql = "INSERT OR REPLACE INTO latest_snapshot ({0}) VALUES ({1})".format(col_names, placeholders)
        insert_sql = "INSERT INTO timeseries ({0}) VALUES ({1})".format(col_names, placeholders)

        data = [[r[c] for c in cols] for r in rows]
        conn.executemany(upsert_sql, data)
        conn.executemany(insert_sql, data)

        _purge_old_records(conn, RETENTION_DAYS)
        conn.commit()
        conn.close()
        print("[DataExport] wrote {0} rows at {1}".format(len(rows), now_str))

    except Exception as e:
        print("[DataExport] DB write error: " + str(e))
